  function parseServerMessage(payload) {
    if (!payload) return null;
    if (payload._server_messages) {
      try {
        var messages = JSON.parse(payload._server_messages);
        if (messages.length) {
          var first = JSON.parse(messages[0]);
          if (first.message) return first.message.replace(/<[^>]*>/g, '');
        }
      } catch (error) {
        return payload._error_message || payload.exception || null;
      }
    }
    return payload._error_message || payload.exception || null;
  }
  function api(method, args) {
    return getCsrfToken().then(function (csrfToken) {
      var body = new URLSearchParams();
      Object.keys(args || {}).forEach(function (key) {
        var value = args[key];
        body.set(key, typeof value === 'string' ? value : JSON.stringify(value));
      });
      return fetch('/api/method/' + method, {
        method: 'POST',
        credentials: 'same-origin',
        headers: {'Content-Type': 'application/x-www-form-urlencoded', 'X-Frappe-CSRF-Token': csrfToken},
        body: body
      }).then(function (response) {
        return response.text().then(function (text) {
          var payload = text ? JSON.parse(text) : {};
          if (!response.ok) throw new Error(parseServerMessage(payload) || ('Request failed: ' + response.status));
          return payload.message || payload;
        });
      });
    });
  }
  function hasWarehouseRole() {
    var roles = frappe.user_roles || [];
    return roles.indexOf('3PL Warehouse User') !== -1 || roles.indexOf('3PL Warehouse Manager') !== -1 || roles.indexOf('System Manager') !== -1;
  }

  var sourceContainers = [];
  function setStatus(message, isError) {
    var target = byId('repack-status');
    if (!target) return;
    target.textContent = message || '';
    target.className = isError ? 'text-danger small' : 'text-muted small';
  }
  function requireWarehouseRole() {
    if (frappe.user_roles && !hasWarehouseRole()) {
      setStatus('This scanner page is only available to warehouse users.', true);
      var button = byId('apply-repack');
      if (button) button.disabled = true;
      return false;
    }
    return true;
  }
  function renderSources() {
    var list = byId('repack-source-list');
    if (!list) return;
    list.innerHTML = sourceContainers.length ? sourceContainers.map(function (name) {
      return '<li class="list-group-item d-flex justify-content-between align-items-center">' + name + '<button class="btn btn-sm btn-outline-danger" data-source="' + name + '">Remove</button></li>';
    }).join('') : '<li class="list-group-item text-muted">No source containers scanned.</li>';
  }
  function addSource() {
    var input = byId('repack-source-container');
    var value = (input.value || '').trim();
    if (!value) return;
    if (sourceContainers.indexOf(value) === -1) sourceContainers.push(value);
    input.value = '';
    renderSources();
    input.focus();
  }
  function togglePartialFields() {
    var fields = byId('partial-repack-fields');
    if (fields) fields.style.display = byId('repack-mode').value === 'Partial Split' ? '' : 'none';
  }
  function applyRepack() {
    if (frappe.session && frappe.session.user === 'Guest') {
      window.location.href = '/login?redirect-to=' + encodeURIComponent('/warehouse/repack');
      return;
    }
    if (!requireWarehouseRole()) return;
    var mode = byId('repack-mode').value;
    var targetContainer = (byId('repack-target-container').value || '').trim();
    var targetLocation = (byId('repack-target-location').value || '').trim();
    if (!sourceContainers.length || !targetContainer || !targetLocation) {
      setStatus('Scan source container(s), target container, and target location first.', true);
      return;
    }
    setStatus('Applying repack...', false);
    api('erpnext_3pl.api.warehouse_ops.apply_container_repack', {
      repack_mode: mode,
      source_containers: sourceContainers,
      target_container: targetContainer,
      target_location: targetLocation,
      item_code: (byId('repack-item').value || '').trim(),
      qty: (byId('repack-qty').value || '').trim(),
      uom: (byId('repack-uom').value || '').trim() || 'Nos'
    }).then(function (result) {
      setStatus('Repack applied: ' + result.repack + ' / ' + result.movement + '.', false);
      sourceContainers = [];
      renderSources();
      byId('repack-target-container').value = '';
      byId('repack-target-location').value = '';
      byId('repack-item').value = '';
      byId('repack-qty').value = '';
      byId('repack-source-container').focus();
    }).catch(function (error) {
      setStatus(error.message || 'Could not apply repack.', true);
    });
  }
  frappe.ready(function () {
    if (frappe.session && frappe.session.user === 'Guest') {
      window.location.href = '/login?redirect-to=' + encodeURIComponent('/warehouse/repack');
      return;
    }
    requireWarehouseRole();
    renderSources();
    togglePartialFields();
    var add = byId('add-repack-source');
    if (add) add.addEventListener('click', addSource);
    var sourceInput = byId('repack-source-container');
    if (sourceInput) sourceInput.addEventListener('keydown', function (event) {
      if (event.key === 'Enter') { event.preventDefault(); addSource(); }
    });
    var list = byId('repack-source-list');
    if (list) list.addEventListener('click', function (event) {
      var button = event.target.closest('button[data-source]');
      if (!button) return;
      sourceContainers = sourceContainers.filter(function (name) { return name !== button.getAttribute('data-source'); });
      renderSources();
    });
    var mode = byId('repack-mode');
    if (mode) mode.addEventListener('change', togglePartialFields);
    var apply = byId('apply-repack');
    if (apply) apply.addEventListener('click', applyRepack);
  });
})();

(function () {
  function byId(id) { return document.getElementById(id); }
  function setStatus(message, isError) {
    var target = byId('correction-review-status');
    if (!target) return;
    target.textContent = message || '';
    target.className = isError ? 'small text-danger' : 'small text-muted';
  }
  function getCsrfToken() {
    if (frappe.csrf_token && frappe.csrf_token !== 'None') return Promise.resolve(frappe.csrf_token);
    if (window.__threePlCsrfTokenPromise) return window.__threePlCsrfTokenPromise;
    window.__threePlCsrfTokenPromise = fetch('/app', { credentials: 'same-origin' })
